INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_official_2026_03', '联合培养专业是否能够转入转出？若能，范围如何？', '本项目学生来自计划内全日制统一招生，被录取为该项目的本科生在读期间不得转入项目外其他专业（即不可转入普通本科专业），本校其他普通专业学生符合接收条件者可申请转入该项目内专业。
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_official_2026_04', '是否一定要出国?出国是否存在选拔?不出国能否有双学位?不出国的毕业证、学位证上的内容是否有区别?', '可以。除金融学中澳班外，其他中外联合培养项目均可选择不出国，通过在地国际化在国内完成学业。\n\n不同项目的出国要求：\n- 金融学中澳班：属于定向出国培养项目，报考时需有明确的出国意向，不适合明确选择不出国的同学。\n- 其他联培项目（计算机、通信工程、人工智能、英语、会计学、金融学国际班、法学等）：鼓励出国，但允许因个人原因选择在地国际化，留在五邑大学按国际化培养模式完成后续学业。\n\n选择不出国（在地国际化）的影响：\n- 仅授予五邑大学学士学位和本科毕业证\n- 无法获得国外合作院校的学位\n- 出国无额外选拔考试，凡修读完国内阶段课程且英语达到合作院校要求的学生，均可申请出国\n- 选择不出国无需提供证明，留在原班级编制，不重新分配班级\n\n具体以当年官方通知为准。', '出国政策', '[-0.07431403,0.020217787,-0.031613268,0.02968587,-0.06429952,-0.008221238,0.024996536,0.045899842,-0.000333134,0.035269357,-0.020466162,0.037792854,-0.031931188,0.015160856,0.005821928,0.034772605,0.03991895,0.010908663,-0.040475313,0.033878453,-0.038408827,-0.015945723,0.019929672,0.002304927,0.086395025,0.05345046,-0.033580404,-0.0022415912,0.020943044,-0.05937174,-0.034414943,0.0062839068,0.12168425,-0.06481614,-0.010660288,-0.031394694,-0.024122253,-0.043912835,-0.03552767,0.008668314,-0.025453547,0.040892586,-0.02938782,-0.048721388,0.03266638,-0.082262054,-0.015439037,-0.02291018,-0.046972822,0.012766514,-0.021042394,0.008643476,0.03262664,-0.070141315,0.0071283844,0.02259226,-8.142068e-05,0.06219329,-0.01791286,-0.04359491,0.012349242,0.008260977,-0.013571251,0.024599135,-0.029010288,0.054404225,0.06422003,0.02626822,-0.017505523,-0.032567028,-0.030023662,0.009418408,-0.026149,-0.037792854,-0.06819405,0.003124567,-0.005205956,-0.03330222,0.012667163,-0.034732867,0.047886845,-0.013342746,0.0023856491,0.06290861,0.0085292235,-0.03880623,0.021817327,0.0135811865,0.015518517,0.019085193,-0.04943671,-0.032209367,0.02287044,-0.046336982,0.010739768,0.018002275,-0.03930298,-0.005156281,0.027122634,-0.0053549814,0.044548675,0.02269161,-0.05635149,-0.024241474,-0.018181106,0.0005650548,0.034554034,0.024161994,-0.021062264,-0.000860622,0.025870819,0.044230755,0.046456203,-0.0321895,-0.009324026,-0