INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_012', '是不是不考虑出国，报中外合作的专业也是可以的，国内最后一学期申请不出国是可以同意继续留在五邑大学学习2年不强制出国的，学历证书和普通的五邑大学毕业生的证书是一样的吗', '可以。除金融学中澳班外，其他中外联合培养项目均可选择不出国，通过在地国际化在国内完成学业。\n\n不同项目的出国要求：\n- 金融学中澳班：属于定向出国培养项目，报考时需有明确的出国意向，不适合明确选择不出国的同学。\n- 其他联培项目（计算机、通信工程、人工智能、英语、会计学、金融学国际班、法学等）：鼓励出国，但允许因个人原因选择在地国际化，留在五邑大学按国际化培养模式完成后续学业。\n\n选择不出国（在地国际化）的影响：\n- 仅授予五邑大学学士学位和本科毕业证\n- 无法获得国外合作院校的学位\n- 出国无额外选拔考试，凡修读完国内阶段课程且英语达到合作院校要求的学生，均可申请出国\n- 选择不出国无需提供证明，留在原班级编制，不重新分配班级\n\n具体以当年官方通知为准。', '学位认证', NULL, true, 3, '2026-06-12 21:32:25.122', '2026-06-17 03:39:46.045', '{不出国可以报吗,不强制出国,证书一样,学历证书,中外合作,中外联合培养,不出国能报吗,证书有区别吗,毕业证有标注吗,不出国证书}', '{不出国,证书,一样,学历,中外合作,联合培养,不强制}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_patch_chuguo_01', '中外联合培养项目能否不出国？是否必须出国？', '可以。除金融学中澳班外，其他中外联合培养项目均可选择不出国，通过在地国际化在国内完成学业。\n\n不同项目的出国要求：\n- 金融学中澳班：属于定向出国培养项目，报考时需有明确的出国意向，不适合明确选择不出国的同学。\n- 其他联培项目（计算机、通信工程、人工智能、英语、会计学、金融学国际班、法学等）：鼓励出国，但允许因个人原因选择在地国际化，留在五邑大学按国际化培养模式完成后续学业。\n\n选择不出国（在地国际化）的影响：\n- 仅授予五邑大学学士学位和本科毕业证\n- 无法获得国外合作院校的学位\n- 出国无额外选拔考试，凡修读完国内阶段课程且英语达到合作院校要求的学生，均可申请出国\n- 选择不出国无需提供证明，留在原班级编制，不重新分配班级\n\n具体以当年官方通知为准。', '出国政策', '[-0.05926454,0.02270294,-0.019593624,0.017283846,-0.06799037,-0.020551095,-0.0007828812,0.042326175,0.0025960316,0.03136954,-0.023354415,0.060962327,-0.028388545,0.017125912,0.014934585,0.013937631,0.050064918,0.0032228304,-0.022169914,0.04880145,-0.034133375,-0.022031723,0.012535971,-0.031112898,0.09697116,0.025387809,-0.023828216,-0.012131266,0.02611825,-0.043471195,-0.021163087,0.006648013,0.12002945,-0.05886971,-0.025723416,-0.035535034,0.022308106,-0.04978853,-0.06700328,0.027105335,-0.03662083,0.020185875,-0.029336145,-0.03861474,0.028704412,-0.075018406,-0.030579872,-0.024420466,-0.063726164,0.02562471,-0.014835877,-0.0005947183,0.0003686143,-0.0503413,0.02904002,0.013720472,-0.008148381,0.046669345,-0.02961253,-0.030520648,0.03209998,0.0035929868,-0.014589106,-0.0059027644,-0.034824334,0.054131705,0.045761228,0.053815838,-0.031566955,-0.014292981,-0.044300344,0.0018964357,-0.013789568,-0.030994447,-0.07280734,0.019642977,-0.017195009,-0.021696113,0.034844074,-0.036956437,0.04907783,-0.017619455,0.006776334,0.091759354,0.009816553,-0.03407415,0.010502577,0.01732333,0.01862628,0.006978686,-0.036778763,-0.033106808,0.026197217,-0.024262533,-0.0016262213,0.03200127,-0.010640769,0.00034671335,0.015319549,-0.0072402633,0.055790003,0.01886318,-0.05124942,-0.03065884,-0.026078768,-0.019958844,0.021498697,0.019406078,-0.024519173,-0.007289618,0.021143345,0.022545006,0.026552567,-0.029770464,-0.006110052,-0.0020753448,0.026