INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_official_2026_19', '后续不出国需要提供证明吗？剩下两年要混班吗？', '可以。除金融学中澳班外，其他中外联合培养项目均可选择不出国，通过在地国际化在国内完成学业。\n\n不同项目的出国要求：\n- 金融学中澳班：属于定向出国培养项目，报考时需有明确的出国意向，不适合明确选择不出国的同学。\n- 其他联培项目（计算机、通信工程、人工智能、英语、会计学、金融学国际班、法学等）：鼓励出国，但允许因个人原因选择在地国际化，留在五邑大学按国际化培养模式完成后续学业。\n\n选择不出国（在地国际化）的影响：\n- 仅授予五邑大学学士学位和本科毕业证\n- 无法获得国外合作院校的学位\n- 出国无额外选拔考试，凡修读完国内阶段课程且英语达到合作院校要求的学生，均可申请出国\n- 选择不出国无需提供证明，留在原班级编制，不重新分配班级\n\n具体以当年官方通知为准。', '在地国际化', '[-0.05423257,-0.0004460399,-0.060580604,-0.0068623405,-0.067986645,0.017310144,-0.0075137974,0.038362492,-0.018485704,0.035619516,0.013656107,0.0865997,-0.003078502,0.043691706,0.043613333,0.011892764,0.04694409,0.0056328992,-0.051254485,0.026450135,-0.030309895,-0.028056735,0.022609968,-0.0051087947,0.07739113,0.04067443,-0.04184999,-0.00554963,0.03844086,-0.033993322,-0.012362989,0.005833724,0.079899,-0.038519233,-0.01335242,-0.01364631,0.010844556,0.0057602515,-0.08777526,0.0061178184,-0.013548347,0.049647883,-0.048472323,-0.005260638,0.0075725755,-0.018172223,-0.017496275,-0.04329985,-0.009438779,-0.008694258,-0.000119546035,0.026469728,0.024530051,-0.053683978,0.0076509463,0.015419449,0.031740163,0.029526187,-0.0029584966,-0.045964457,0.00057492306,0.028370218,-0.036011368,0.00480021,-0.045141563,0.028762072,0.042986367,0.0026156243,-0.014067553,-0.03654037,-0.01665379,0.011598874,-0.019484933,-0.03536481,-0.09968762,0.008444451,0.01949473,-0.014763094,0.03579585,-0.030995639,0.04592527,0.0143222585,0.020043325,0.0884806,0.029506594,-0.02874248,0.05137204,0.009042027,0.0042883507,0.046904907,-0.060345493,-0.025372537,0.017956702,-0.03558033,-0.008826508,-0.00560351,-0.028193884,-0.003987113,0.026234616,0.010276367,0.051097743,0.0031887107,-0.01426348,-0.018975522,-0.071787626,-0.00105923,0.050588332,0.05478117,-0.02780203,-0.009742467,0.046003643,0.0065194685,-0.0043765176,-0.013558143,-0.005740659,-0.0030711545,-