INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_004', '这些项目全要英语？小语种的可以报吗', '是的。本校公共外语教学为英语，非英语语种考生需慎重报考，小语种的不建议报读。', '招生条件', NULL, true, 4, '2026-06-12 21:32:25.122', '2026-06-15 12:17:13.437', '{小语种,日语,法语,非英语,语言要求,小语种能报吗,学日语能报吗,不是英语能报吗,外语不是英语}', '{小语种,语种,英语,报考,语言}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_002', '后两年不出国这个中外的计算机科学与技术专业不出国的课程有没有区别？毕业证是不是只有国内的？', '出国的同学修读外方学校课程，不出国的修读五邑大学课程，课程不一样。不出国的只有五邑大学的学位证和毕业证。', '培养方案', NULL, true, 2, '2026-06-12 21:32:25.122', '2026-06-15 15:39:50.775', '{不出国课程,毕业证,学位证,课程区别,计算机不出国,课程一样吗,不出国有什么证,毕业证一样吗,不出国发什么证,课程跟出国一样吗}', '{不出国,课程,毕业证,学位证,计算机,区别}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_003', '不出国的后续学习可以理解为跟国内普通班的教学内容一样吗？', '学习内容基本一样，区别是有一部分课程双语授课。', '培养方案', NULL, true, 0, '2026-06-12 21:32:25.122', '2026-06-12 21:32:25.122', '{普通班,教学内容,双语,课程一样,和普通班一样吗,跟普通专业一样吗,不出国跟普通班,教学内容区别,课程内容}', '{普通班,教学,内容,双语,一样}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_008', '外省的也可以报考吗？', '我们外省初定江西、福建两个省份招生，但最终须以该省考试院公布为准。若其他省份希望就读中外联培项目，可报考普通类专业，被录取进校后，申请转入中外联培专业就读。', '招生条件', NULL, true, 1, '2026-06-12 21:32:25.122', '2026-06-12 13:34:20.175', '{外省,省外,外省报考,其他省份,江西,福建,省外考生,外省能报吗,广东以外能报吗,其他省能报吗}', '{外省,省外,报考,省份,江西,福建}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_011', '上课是全英文授课吗？', '部分课程是双语授课。', '教学方式', NULL, true, 3, '2026-06-12 21:32:25.122', '2026-06-16 07:21:39.218', '{全英文,英文授课,双语,授课语言,全英,中英双语,英语教学吗,上课用什么语言,中文还是英文}', '{全英文,英文,双语,授课,教学}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_007', '不需要考雅思才能报志愿吧', '不需要。', '招生条件', NULL, true, 0, '2026-06-12 21:32:25.122', '2026-06-12 21:32:25.122', '{雅思报志愿,报考雅思,雅思要求,考雅思,报志愿要雅思吗,不考雅思能报吗,雅思多少分,雅思条件}', '{雅思,报志愿,报考,志愿,不需要}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_009', '在地国际化是大一上学期就申请吗？还是可以到时候看情况再决定？', '国内学习阶段最后一学期申请。', '培养方案', NULL, true, 0, '2026-06-12 21:32:25.122', '2026-06-12 21:32:25.122', '{在地国际化申请,什么时候申请,大一申请,申请时间,什么时候决定,什么时候选,大一就要决定吗,可以后面再决定吗,不出国什么时候申请}', '{在地国际化,申请,时间,大一,最后一学期}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_010', '中外联合培养的英语专业，是纯英语吗？', '英语专业就是主要专攻英语，之后发展方向大致有文学、语言学、翻译等，国外合作学校的方向您也可以查看简章内容。', '专业详情', NULL, true, 0, '2026-06-12 21:32:25.122', '2026-06-12 21:32:25.122', '{纯英语,英语方向,英语专业方向,英语学什么,英语专业学什么,英语课程,英语专业内容}', '{英语,纯英语,方向,专业,文学,语言学,翻译}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_014', '中外联合培养也有保研资格吗', '五邑大学是有推免资格的，中外联培项目学生享受普通专业学生一样的待遇。', '深造升学', NULL, true, 1, '2026-06-12 21:32:25.122', '2026-06-17 03:40:18.526', '{保研,推免,保研资格,推免资格,考研,升学,能保研吗,有推免吗,可以保研吗,保研名额}', '{保研,推免,资格,升学,考研,待遇}');
INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_015', '会计学专业中外联合培养，本科阶段如果选择不出国，那么申请国外的研究生对比普通专业学生，还有优势吗？', '不出国申请国外硕士优势是有，因为我们联培授课都是全英或双语，学生英文水平肯定比普通专业好。但是如果你选择出国的话，申请国外的硕士会更容易，而且会申请到更好的硕士学校，这也是我们这个项目的优势之一。', '深造升学', NULL, true, 0, '2026-06-12 21:32:25.122', '2026-06-12 21:32:25.122', '{申请国外硕士,出国读研,留学优势,考研优势,不出国申请硕士,英文优势,不出国能申请国外硕士吗,不出国读研有优势吗,出国读研好吗}', '{申请,国外,硕士,优势,留学,英文,不出国}');
