INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_006', '假设我第一志源填的是会计，但我只有500分，服从了专业调剂，被调档。按学校录取原则尽量满足第一志愿，是不是可以读会计专业？', '提档到该专业组后，学校会优先考虑您填报的第一志愿专业进行录取。具体以当年官方通知为准。', '录取数据', NULL, true, 6, '2026-06-12 21:32:25.122', '2026-06-17 02:09:34.975', '{服从调剂,第一志愿,调剂,志愿,会计录取,500分,调档,分数不够,能读第一志愿吗,调剂到别的专业吗,服从调剂能读会计吗}', '{服从,调剂,第一志愿,录取,会计,调档}');
