INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_official_2026_30', '请问会计专业一定要出国吗？什么情况下可以不出国？', '可以。除金融学中澳班外，其他中外联合培养项目均可选择不出国，通过在地国际化在国内完成学业。\n\n不同项目的出国要求：\n- 金融学中澳班：属于定向出国培养项目，报考时需有明确的出国意向，不适合明确选择不出国的同学。\n- 其他联培项目（计算机、通信工程、人工智能、英语、会计学、金融学国际班、法学等）：鼓励出国，但允许因个人原因选择在地国际化，留在五邑大学按国际化培养模式完成后续学业。\n\n选择不出国（在地国际化）的影响：\n- 仅授予五邑大学学士学位和本科毕业证\n- 无法获得国外合作院校的学位\n- 出国无额外选拔考试，凡修读完国内阶段课程且英语达到合作院校要求的学生，均可申请出国\n- 选择不出国无需提供证明，留在原班级编制，不重新分配班级\n\n具体以当年官方通知为准。', '会计专业', '[-0.08174624,0.023749027,-0.022141222,0.011264322,-0.02212185,0.03409322,-0.029502258,0.03380265,0.030122135,0.048699066,-0.0015436383,0.054277956,-0.0216182,0.011206209,0.059895586,0.04579339,0.059159484,-0.0073271366,-0.049900077,0.05575016,-0.025376203,-0.0132208085,-0.004351244,-0.06810895,0.036553357,0.046839435,-0.037095748,-0.0025230919,0.038083676,-0.053425625,0.0024129185,-0.013627602,0.04842787,-0.032814723,0.00523021,0.009477334,-0.015429119,-0.034887437,-0.064234726,0.014644587,0.015923083,0.013162695,-0.02649973,-0.010770358,0.012184451,-0.044553638,-0.043778792,-0.03903286,-0.07206067,0.009094753,0.00479678,-0.0066491463,0.071324565,-0.119481236,0.0033899508,0.036785807,0.024272047,0.009346578,-0.020204106,-0.014257165,-0.021327633,-0.00045219524,-0.004857315,0.018586615,0.021366376,0.0058065015,0.022548016,-0.016417047,-0.028107535,-0.031458743,-0.0070849974,-0.050597437,-0.03849047,-0.039788336,-0.10243463,-0.014663959,0.004554641,-0.007748459,0.006687889,-0.060980372,0.04002079,-0.004363351,0.0068234866,0.06299497,0.0022301034,-0.024155822,0.032330446,-0.019719828,0.023322862,0.02125015,-0.0226255,-0.011797029,0.019283976,-0.0315556,-0.009564504,0.013065839,-0.038897265,0.019070895,0.020978952,0.023516573,0.07574119,0.018722214,-0.02768137,-0.016843213,-0.014276535,-0.03663084,0.0064651202,0.06783776,-0.0007560801,-0.010324822,0.028320618,0.014450876,0.032834094,-0.03002528,-0.015322577,-0.0030049493,