INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('cmqg9q9l7000lf7vnbuucapud', '金融学中澳班可以转国际班吗', '本专业的物理（再选化学）考生可申请转入中外联合培养项目的计算机科学与技术、通信工程、人工智能、英语、金融学、法学专业；其他类别考生只可申请转入中外联合培养项目的英语、金融学、法学专业。国际教育学院将根据学生考核情况选拔录取学生，原则上，转入专业接收人数的上限控制在该专业当年计划招生人数的15%以内，具体要求参见《2025年国际教育学院本科学生转专业工作实施方案》。', NULL, '[-0.04807022,0.014358382,-0.047325853,-0.0031072283,-0.07357447,0.013819698,-0.0063956506,0.021410247,0.044622637,0.042663787,0.025876429,0.05504373,-0.013212454,0.044426754,0.03208599,-0.015259454,0.021939138,-0.002889306,-0.023212392,0.014632621,-0.044936053,0.01207632,-0.01623888,-0.054299366,0.033085003,0.03208599,-0.051008496,-0.02254638,0.032262284,-0.05320241,0.014652209,0.0318901,0.023525808,-0.039666746,0.022193788,-0.00301908,0.017854933,-0.0010186029,-0.09825599,0.013173277,-0.019980285,-0.02955907,-0.031635452,0.0072869277,0.019079214,-0.03353554,-0.026444497,-0.012242822,-0.0095983725,0.022644324,-0.01939263,0.013467104,-0.003660604,-0.06667931,0.0291673,-0.015102746,0.04450511,-0.02601355,-0.035474803,-0.069617584,0.017708018,0.0015499413,0.018550325,-0.009730595,-0.0001327581,0.04658149,0.01476974,-0.017737402,-0.026366143,-0.030283846,-0.018236907,-0.018814769,-0.0013565047,-0.011723727,-0.10624811,0.015954847,-0.01932407,0.004745318,0.081096455,-0.033731423,0.064328685,0.032771587,-0.004069514,0.04920635,-0.0103133535,0.00013107472,0.049363058,0.024975358,0.03588616,0.028266229,-0.07412294,-0.020705061,0.023564985,-0.024348525,-0.02744351,0.029128123,-0.0005010375,0.055788092,-0.014564062,-0.015954847,0.059862506,0.07784476,-0.008070469,-0.023662927,-0.042467903,0.0034524759,-0.0028942032,0.08799161,-0.02242885,-0.01743378,0.030205492,0.026562028,-0.0059010405,7.973138e-05,-0.009647344,0.0039152545,-0.016268263,-0.011753109,0.026640382,-0.008555284,-0.020019462,-0.043212265,0.04446593,-0.0067923176,0.01168455,-0.029265242,0.04920635,0.046033014,-0.035827395,0.0046718