INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_official_2026_23', '是不是可以理解为除了中澳班必须出国，其他的项目都可以选择不出国？', '可以。除金融学中澳班外，其他中外联合培养项目均可选择不出国，通过在地国际化在国内完成学业。\n\n不同项目的出国要求：\n- 金融学中澳班：属于定向出国培养项目，报考时需有明确的出国意向，不适合明确选择不出国的同学。\n- 其他联培项目（计算机、通信工程、人工智能、英语、会计学、金融学国际班、法学等）：鼓励出国，但允许因个人原因选择在地国际化，留在五邑大学按国际化培养模式完成后续学业。\n\n选择不出国（在地国际化）的影响：\n- 仅授予五邑大学学士学位和本科毕业证\n- 无法获得国外合作院校的学位\n- 出国无额外选拔考试，凡修读完国内阶段课程且英语达到合作院校要求的学生，均可申请出国\n- 选择不出国无需提供证明，留在原班级编制，不重新分配班级\n\n具体以当年官方通知为准。', '中澳班政策', '[-0.045958906,0.01031254,-0.029653419,-0.00037121496,-0.05117355,-0.016743286,-0.019613285,0.030139858,-0.011246506,0.0438964,0.010059591,0.048021413,-0.010818439,-0.0073647103,0.074211374,0.020313758,0.04681504,0.04436338,-0.04280677,0.029595045,-0.05074548,-0.036658164,-0.0022485715,-0.011878879,0.047943585,0.025606232,-0.04323484,-0.009018608,0.01694759,-0.06549436,0.0011084764,0.0031837537,0.06440473,-0.068607576,-0.0059540328,-0.004144474,0.014087319,-0.0044630924,-0.07281043,0.032805555,-0.040082704,0.008371643,-0.02562569,0.0050249314,0.038837418,-0.05288582,-0.02192874,-0.036950026,-0.009359117,-0.016023353,-0.025995385,0.023855045,0.014564031,-0.1133212,0.027571453,-0.00321294,0.027960604,0.0017098386,-0.04436338,-0.023057284,0.017823182,0.024750097,-0.009237506,0.003609389,-0.014787794,0.041211247,0.05237992,0.0004447891,-0.03946006,0.007301473,-0.014962913,-0.009923388,-0.02340752,-0.03202725,-0.09425273,-0.010604405,0.0053605754,-0.020722369,0.03428433,-0.034809686,0.05650494,-0.0071214903,-0.0051319483,0.06335402,0.03724189,-0.032124534,0.024302572,0.027882773,0.03850664,0.024010707,-0.06619483,-0.011771862,0.018329082,-0.03428433,-0.029342096,0.0067420667,-0.019944064,0.023212945,0.012754472,-0.007549558,0.07705219,0.044246636,-0.059229005,-0.014505658,-0.044674702,-0.008318134,0.01759942,0.030898705,-0.016791929,0.0018229361,0.037689418,0.023699386,0.0064404733,0.008191659,-0.017365929,0.011859