INSERT INTO public."FaqItem" (id, question, answer, category, embedding, "isActive", "hitCount", "createdAt", "updatedAt", aliases, keywords) VALUES ('faq_qa_013', '老师请问不出国需要申请，不可抗力是指哪些呢？如果没有特殊的，就单纯不想出国，可以留国内读完吗', '可以。除金融学中澳班外，其他中外联合培养项目均可选择不出国，通过在地国际化在国内完成学业。\n\n不同项目的出国要求：\n- 金融学中澳班：属于定向出国培养项目，报考时需有明确的出国意向，不适合明确选择不出国的同学。\n- 其他联培项目（计算机、通信工程、人工智能、英语、会计学、金融学国际班、法学等）：鼓励出国，但允许因个人原因选择在地国际化，留在五邑大学按国际化培养模式完成后续学业。\n\n选择不出国（在地国际化）的影响：\n- 仅授予五邑大学学士学位和本科毕业证\n- 无法获得国外合作院校的学位\n- 出国无额外选拔考试，凡修读完国内阶段课程且英语达到合作院校要求的学生，均可申请出国\n- 选择不出国无需提供证明，留在原班级编制，不重新分配班级\n\n具体以当年官方通知为准。', '培养方案', NULL, true, 2, '2026-06-12 21:32:25.122', '2026-06-16 06:41:14.806', '{不想出国,可以不出国吗,必须出国吗,留国内,不可抗力,单纯不想出国,中澳班必须出国,不出国行吗,能不出国吗,一定要出国吗}', '{不想出国,留国内,必须出国,不出国,不可抗力,中澳班}');
